import os
import sys

# 检查环境变量和临时目录
tmp_dirs = [
    os.environ.get('TMPDIR', '/tmp'),
    '/private/tmp',
    '/var/tmp',
]

print('检查临时目录:')
for tmp_dir in tmp_dirs:
    if os.path.exists(tmp_dir):
        print(f'  {tmp_dir}')
        # 查找 Excel 文件
        for root, dirs, files in os.walk(tmp_dir):
            for f in files:
                if 'messy' in f.lower() and (f.endswith('.xlsx') or f.endswith('.xls')):
                    full_path = os.path.join(root, f)
                    print(f'    ✓ 找到: {full_path}')
            break  # 只检查顶层目录

